fun main() {
    // Creates a set with duplicate 2s and 3s
    val numbers = setOf(1, 2, 2, 3, 3, 3)

    // The Set silently crushed the duplicates out of existence!
    println(numbers) // Prints: [1, 2, 3]
}

fun main() {
    // Creates a map pointing Country -> Capital
    val capitals = mapOf("France" to "Paris", "Japan" to "Tokyo")

    // We use the Key ["Japan"] to retrieve the Value
    println(capitals["Japan"]) // Prints: Tokyo
}
